  'Sales pay out to you at handover. Tap to manage.': { en: 'Sales pay out to you at handover. Tap to manage.', es: 'Las ventas se te pagan en la entrega. Toca para gestionar.', de: 'Verkäufe werden dir bei der Übergabe ausgezahlt. Zum Verwalten tippen.', da: 'Salg udbetales til dig ved overdragelsen. Tryk for at administrere.', sv: 'Försäljningar betalas ut till dig vid överlämning. Tryck för att hantera.', nl: 'Verkopen worden bij overdracht aan je uitbetaald. Tik om te beheren.', fr: 'Les ventes vous sont versées à la remise. Appuyez pour gérer.', pt: 'As vendas são-te pagas na entrega. Toca para gerir.' },
  'Connect Stripe to receive money from sales.': { en: 'Connect Stripe to receive money from sales.', es: 'Conecta Stripe para recibir el dinero de las ventas.', de: 'Verbinde Stripe, um Geld aus Verkäufen zu erhalten.', da: 'Forbind Stripe for at modtage penge fra salg.', sv: 'Anslut Stripe för att ta emot pengar från försäljning.', nl: 'Koppel Stripe om geld van verkopen te ontvangen.', fr: 'Connectez Stripe pour recevoir l\'argent des ventes.', pt: 'Liga o Stripe para receber o dinheiro das vendas.' },
