  'This is the address you sign in with. Changing it sends a confirmation link to the new address — your email only changes once you click that link.': { en: 'This is the address you sign in with. Changing it sends a confirmation link to the new address — your email only changes once you click that link.', es: 'Es la dirección con la que inicias sesión. Al cambiarla se envía un enlace de confirmación a la nueva dirección — tu correo solo cambia cuando haces clic en ese enlace.', de: 'Mit dieser Adresse meldest du dich an. Beim Ändern wird ein Bestätigungslink an die neue Adresse gesendet — deine E-Mail ändert sich erst, wenn du auf den Link klickst.', da: 'Det er den adresse, du logger ind med. Når du ændrer den, sendes et bekræftelseslink til den nye adresse — din e-mail ændres først, når du klikker på linket.', sv: 'Det är adressen du loggar in med. När du ändrar den skickas en bekräftelselänk till den nya adressen — din e-post ändras först när du klickar på länken.', nl: 'Dit is het adres waarmee je inlogt. Bij wijziging wordt een bevestigingslink naar het nieuwe adres gestuurd — je e-mail verandert pas als je op die link klikt.', fr: 'C\'est l\'adresse avec laquelle vous vous connectez. La modifier envoie un lien de confirmation à la nouvelle adresse — votre e-mail ne change qu\'après avoir cliqué sur ce lien.', pt: 'É o endereço com que inicias sessão. Ao alterá-lo é enviado um link de confirmação para o novo endereço — o teu e-mail só muda quando clicares nesse link.' },
  'Current email': { en: 'Current email', es: 'Correo actual', de: 'Aktuelle E-Mail', da: 'Nuværende e-mail', sv: 'Nuvarande e-post', nl: 'Huidige e-mail', fr: 'E-mail actuel', pt: 'E-mail atual' },
  'New email': { en: 'New email', es: 'Nuevo correo', de: 'Neue E-Mail', da: 'Ny e-mail', sv: 'Ny e-post', nl: 'Nieuwe e-mail', fr: 'Nouvel e-mail', pt: 'Novo e-mail' },
  'Confirmation sent to {email}. Click the link in that email to finish the change. (Check spam if it doesn’t arrive.)': { en: 'Confirmation sent to {email}. Click the link in that email to finish the change. (Check spam if it doesn’t arrive.)', es: 'Confirmación enviada a {email}. Haz clic en el enlace de ese correo para completar el cambio. (Revisa el spam si no llega.)', de: 'Bestätigung an {email} gesendet. Klicke auf den Link in dieser E-Mail, um die Änderung abzuschließen. (Prüfe den Spam-Ordner, falls sie nicht ankommt.)', da: 'Bekræftelse sendt til {email}. Klik på linket i e-mailen for at fuldføre ændringen. (Tjek spam, hvis den ikke kommer.)', sv: 'Bekräftelse skickad till {email}. Klicka på länken i e-postmeddelandet för att slutföra ändringen. (Kolla skräpposten om den inte kommer.)', nl: 'Bevestiging verzonden naar {email}. Klik op de link in die e-mail om de wijziging te voltooien. (Controleer spam als hij niet aankomt.)', fr: 'Confirmation envoyée à {email}. Cliquez sur le lien dans cet e-mail pour terminer le changement. (Vérifiez les spams s\'il n\'arrive pas.)', pt: 'Confirmação enviada para {email}. Clica no link desse e-mail para concluir a alteração. (Verifica o spam se não chegar.)' },
  'Send confirmation link': { en: 'Send confirmation link', es: 'Enviar enlace de confirmación', de: 'Bestätigungslink senden', da: 'Send bekræftelseslink', sv: 'Skicka bekräftelselänk', nl: 'Bevestigingslink versturen', fr: 'Envoyer le lien de confirmation', pt: 'Enviar link de confirmação' },
